INSERT INTO `Categories` VALUES (1,'Solar Panels','High-efficiency monocrystalline and polycrystalline solar panels for residential and commercial use','/uploads/categories/solar-panels-1780436634387-497561669.jpg','solar-panels','2026-04-21 21:09:21','2026-06-02 21:43:54'),(2,'Inverters','Pure sine wave inverters for reliable power conversion and grid-tie systems','/uploads/categories/inverters-1780436762461-595024186.jpg','inverters','2026-04-21 21:09:21','2026-06-02 21:46:02'),(3,'Batteries','Deep cycle lithium and lead-acid batteries for energy storage solutions','/uploads/categories/batteries-1780438292191-336832969.png','batteries','2026-04-21 21:09:21','2026-06-02 22:11:39'),(5,'Charge Controllers','MPPT and PWM charge controllers for optimal battery charging','/uploads/categories/charge-controller-1780437969895-566350236.png','charge-controllers','2026-04-21 21:09:21','2026-06-02 22:06:13'),(6,'Accessories','Cables, connectors, mounting brackets and other solar accessories','/uploads/categories/solar-accessories-1780430979290-685928553.jpg','accessories','2026-04-21 21:09:21','2026-06-02 20:09:39'),(9,'Solar Street Lights','Integrated solar street lighting products with LiFePO4 batteries, mono solar panels, LED lighting, and optional radar/camera features.',NULL,'solar-street-lights','2026-06-03 07:33:12','2026-06-03 07:33:12'),(10,'Solar Flood Lights','Solar flood lighting products for outdoor security, yards, compounds, farms, playgrounds, and commercial lighting.',NULL,'solar-flood-lights','2026-06-03 07:33:12','2026-06-03 07:33:12'),(11,'Solar Garden Lights','Decorative and functional solar garden, lawn, pathway, and landscape lighting products.',NULL,'solar-garden-lights','2026-06-03 07:33:12','2026-06-03 07:33:12'),(12,'Solar Strip Lights','Flexible solar strip lighting products for outdoor decoration and low-voltage solar lighting applications.',NULL,'solar-strip-lights','2026-06-03 07:33:12','2026-06-03 07:33:12'),(13,'Solar Batten Lights','Solar-powered batten tube lighting products for areas without grid electricity.',NULL,'solar-batten-lights','2026-06-03 07:33:12','2026-06-03 07:33:12'),(14,'Solar Fans','Portable solar fans with rechargeable battery, solar charging, DC charging, and USB output features.',NULL,'solar-fans','2026-06-03 07:33:12','2026-06-03 07:33:12'),(15,'Energy Storage Systems','Integrated solar energy storage systems, commercial ESS cabinets, and PV + ESS + EV charging solutions.',NULL,'energy-storage-systems','2026-06-03 08:15:37','2026-06-03 08:15:37'),(16,'EV Chargers','Electric vehicle charging systems and DC fast charging equipment for solar and grid-connected installations.',NULL,'ev-chargers','2026-06-03 08:15:37','2026-06-03 08:15:37'),(17,'UPS Systems','Industrial uninterruptible power supply systems for backup and critical power applications.',NULL,'ups-systems','2026-06-03 08:15:37','2026-06-03 08:15:37'),(18,'BIPV Carports','Solar carport structures integrating photovoltaic generation and vehicle sheltering.',NULL,'bipv-carports','2026-06-03 08:15:37','2026-06-03 08:15:37'),(19,'Energy Management Systems','EMS platforms and controllers for monitoring, dispatching, and managing PV, ESS, grid, load, and EV charging systems.',NULL,'energy-management-systems','2026-06-03 08:15:37','2026-06-03 08:15:37'),(20,'Combiner Boxes','PV combiner boxes for solar DC string protection, surge protection, isolation, and inverter input wiring management.',NULL,'combiner-boxes','2026-06-03 08:29:01','2026-06-03 08:29:01');
