INSERT INTO `Products` VALUES (21,1,'Mono half-cell solar panel grade A (550W)',0.00,'','550W','25 years','','','/uploads/products/mono-solar-panel-550w-1780438871224-228970728.jpg',NULL,'','{\"Type\": \"Monocrystalline Half-Cell\", \"Cell Type\": \"Grade A Mono PERC / Half-Cell\", \"Efficiency\": \"21–21.5%\", \"Power Output\": \"550W\", \"Product Warranty\": \"12 years\", \"Performance Warranty\": \"25 years\", \"Open Circuit Voltage (Voc)\": \"~49–50V\", \"Maximum Power Voltage (Vmp)\": \"~41–42V\", \"Power Output after 25 Years\": \"~84–85%\", \"Short Circuit Current (Isc)\": \"~13.5–14A\", \"Maximum Power Current (Imp):\": \"~13A\"}',0,'in_stock','2026-06-02 22:21:13','2026-06-02 22:26:24'),(22,2,'Hybrid Solar Inverter (10.2KW)',0.00,'The SunlinkPower 10.2kW Hybrid Inverter is a high-performance all-in-one solar energy solution designed for residential and commercial applications. It integrates a pure sine wave inverter, intelligent battery management system, and dual MPPT solar charge controller to maximize energy efficiency and system reliability. Compatible with lithium batteries and grid/generator support, it ensures uninterrupted power supply with smart energy prioritization.','10200W','','','','/uploads/products/innverters-1780439545319-375065388.png',NULL,'','{\"weight\": \"27 kg\", \"display\": \"LCD + LED Indicators\", \"warranty\": \"5 Years\", \"ip rating\": \"IP65\", \"mppt type\": \"Dual MPPT\", \"dimensions\": \"620 × 440 × 130 mm\", \"efficiency\": \"98%\", \"monitoring\": \"Mobile App & Remote Monitoring\", \"rated power\": \"10.2kW\", \"built in mppt\": true, \"transfer time\": \"<10ms\", \"cooling method\": \"Intelligent Fan Cooling\", \"battery voltage\": \"48V DC\", \"output waveform\": \"Pure Sine Wave\", \"output frequency\": \"50Hz/60Hz\", \"parallel support\": \"Up to 6 Units\", \"ac output voltage\": \"220V/230V/240V AC\", \"max pv input power\": \"11000W\", \"mppt voltage range\": \"90V - 450V DC\", \"max charging current\": \"160A\", \"max pv input voltage\": \"500V DC\", \"operating temperature\": \"-10°C to +55°C\"}',0,'in_stock','2026-06-02 22:32:26','2026-06-02 22:40:40'),(23,3,'Lithium Battery (51.2v)',0.00,' a high-performance LiFePO4 energy storage solution designed for solar systems, hybrid inverters, and backup power applications. It provides long cycle life, fast charging capability, intelligent BMS protection, and stable energy output for residential and commercial solar installations.','5120W','','LiFePO4','','/uploads/products/battery-1780440534021-572825537.png',NULL,'','{\"energy\": \"5.12kWh\", \"weight\": \"48 kg\", \"voltage\": \"51.2V\", \"capacity\": \"100Ah\", \"warranty\": \"5 Years\", \"ip_rating\": \"IP65\", \"cycle_life\": \"6000+ Cycles\", \"dimensions\": \"580 × 440 × 150 mm\", \"scalability\": \"Up to 15 Units in Parallel\", \"battery_type\": \"LiFePO4\", \"installation\": \"Wall Mounted / Rack Mounted\", \"communication\": \"RS485/CAN/WiFi Optional\", \"cooling_method\": \"Natural Cooling\", \"nominal_voltage\": \"51.2V\", \"charging_voltage\": \"58.4V\", \"nominal_capacity\": \"100Ah\", \"parallel_support\": \"Yes\", \"depth_of_discharge\": \"95%\", \"max_charge_current\": \"100A\", \"storage_temperature\": \"0°C to +45°C\", \"max_discharge_current\": \"100A\", \"operating_temperature\": \"-10°C to +55°C\", \"discharge_cutoff_voltage\": \"44.8V\"}',1,'in_stock','2026-06-02 22:48:56','2026-06-02 23:02:01'),(24,6,'PV Cable 4mm',0.00,'high-performance solar cable designed for safe and efficient DC power transmission in photovoltaic systems. Built with tinned copper conductors and XLPO insulation, it provides excellent UV resistance, heat resistance, flexibility, and long-term outdoor durability.','','','','','/uploads/products/solar-pv-cable-1780467757620-176463921.png',NULL,'','{\"size\": \"4mm²\", \"type\": \"Photovoltaic Cable\", \"standard\": \"EN 50618 / IEC 62930\", \"roll_length\": \"100m\", \"halogen_free\": \"Yes\", \"uv_resistant\": \"Yes\", \"color_options\"